agent_output:
{
  "executive_summary": "Integration architecture for a logistics platform connecting three external systems (SAP ERP via SFTP/XML, DHL Carrier API via REST/webhooks, Analytics via Kafka) using an event-driven backbone with dedicated Anti-Corruption Layers per integration point. The design isolates each external system behind adapter boundaries, uses an internal event bus as the canonical communication layer, and ensures no external system's failure or latency can cascade into the core domain.",

  "architecture": {
    "components": [
      {
        "name": "Core Domain Service",
        "responsibility": "Owns the order and shipment lifecycle. Publishes canonical domain events (OrderPlaced, OrderConfirmed, etc.). Enforces all business invariants.",
        "boundaries": "Accepts commands only through its API. Never directly touches external systems. All state transitions produce domain events published to the Internal Event Bus."
      },
      {
        "name": "Internal Event Bus",
        "responsibility": "Central nervous system. Routes domain events between the core domain and all integration adapters. Kafka topic partitioned by orderId for ordering guarantees.",
        "boundaries": "Only canonical domain events flow here. External system DTOs never appear on this bus. Topics: logistics.orders, logistics.shipments, logistics.deliveries."
      },
      {
        "name": "SAP ERP Adapter (System A)",
        "responsibility": "Anti-Corruption Layer for SAP. Polls SFTP every 15 minutes for inbound XML files (e.g., purchase orders). Transforms confirmed orders into OrderConfirmed commands. For outbound, subscribes to domain events and generates SAP-compatible XML files dropped to an outbound SFTP directory.",
        "boundaries": "Owns the XML schema mapping and SFTP connection lifecycle. Translates between SAP's IDoc/XML vocabulary and the internal ubiquitous language. Idempotent processing via file-name tracking in a processed-files ledger."
      },
      {
        "name": "DHL Carrier Adapter (System B)",
        "responsibility": "Anti-Corruption Layer for DHL. Outbound: calls DHL REST API to create shipments when ShipmentCreated events occur. Inbound: exposes a webhook endpoint that receives DHL status callbacks, translates them into DeliveryAttempted/DeliveryCompleted/DeliveryFailed commands.",
        "boundaries": "Owns the DHL API client, authentication (API key rotation), retry logic, and webhook signature verification. The webhook endpoint must respond within 500ms — it does NOT process inline but instead enqueues to an internal queue and ACKs immediately."
      },
      {
        "name": "Analytics Stream Adapter (System C)",
        "responsibility": "Subscribes to all domain events on the Internal Event Bus and republishes them to the external Analytics Kafka cluster in the analytics-required schema.",
        "boundaries": "Owns schema transformation to the analytics format. Separate Kafka producer with its own delivery guarantees. Uses a dedicated consumer group so it cannot interfere with other consumers. Handles schema evolution via a Schema Registry."
      },
      {
        "name": "Webhook Ingestion Gateway",
        "responsibility": "Lightweight HTTP endpoint that receives DHL webhook callbacks. Validates signatures, enqueues raw payloads to a fast internal queue (Redis Stream or Kafka topic), and returns 200 OK within the 500ms SLA.",
        "boundaries": "Does zero business logic. Its only job is to ACK fast and durably enqueue. Decouples webhook latency from processing latency."
      },
      {
        "name": "SFTP Poller",
        "responsibility": "Scheduled job (every 15 minutes) that connects to SAP's SFTP server, downloads new XML files, and hands them to the SAP ERP Adapter for parsing and command generation.",
        "boundaries": "Owns connection pooling, file-locking semantics, and exactly-once download tracking. Moves processed files to an archive directory on the SFTP server."
      },
      {
        "name": "Dead Letter Queue (DLQ) & Retry Service",
        "responsibility": "Captures failed integration attempts from any adapter. Provides configurable retry with exponential backoff. Alerts on repeated failures.",
        "boundaries": "Per-adapter DLQ topics. Retry policies are configurable per integration (e.g., DHL retries are aggressive due to transient network errors; SAP retries are conservative since files are durable)."
      }
    ],
    "interfaces": [
      {
        "from": "Core Domain Service",
        "to": "Internal Event Bus",
        "contract": "Publishes domain events: {eventType, orderId, timestamp, version, payload}. All events are immutable, versioned, and include a correlation ID.",
        "coupling_type": "event (loose)"
      },
      {
        "from": "SFTP Poller",
        "to": "SAP ERP Adapter",
        "contract": "Passes raw XML byte stream + file metadata (filename, timestamp, checksum).",
        "coupling_type": "function call (internal, tight but contained)"
      },
      {
        "from": "SAP ERP Adapter",
        "to": "Core Domain Service",
        "contract": "Issues ConfirmOrder command: {orderId, sapDocumentNumber, lineItems[], confirmedAt}.",
        "coupling_type": "command (moderate)"
      },
      {
        "from": "Internal Event Bus",
        "to": "DHL Carrier Adapter",
        "contract": "Subscribes to ShipmentCreated events. Calls DHL API: POST /shipments with translated payload. Publishes command results back as domain events.",
        "coupling_type": "event (loose)"
      },
      {
        "from": "Webhook Ingestion Gateway",
        "to": "DHL Carrier Adapter",
        "contract": "Enqueues raw webhook payload to dhl.webhooks.raw topic/stream. Adapter consumes and translates.",
        "coupling_type": "queue (loose)"
      },
      {
        "from": "DHL Carrier Adapter",
        "to": "Core Domain Service",
        "contract": "Issues RecordDeliveryStatus command: {shipmentId, status, attemptTimestamp, failureReason?}.",
        "coupling_type": "command (moderate)"
      },
      {
        "from": "Internal Event Bus",
        "to": "Analytics Stream Adapter",
        "contract": "Subscribes to all domain event topics. Transforms and republishes to external analytics Kafka cluster with analytics-specific schema.",
        "coupling_type": "event (loose)"
      },
      {
        "from": "Any Adapter",
        "to": "DLQ & Retry Service",
        "contract": "Failed messages are routed to per-adapter DLQ topics with original payload + error metadata + retry count.",
        "coupling_type": "event (loose)"
      }
    ],
    "data_flow": "INBOUND FROM SAP: SFTP Poller (every 15min) → downloads XML → SAP Adapter parses/validates → issues ConfirmOrder command → Core Domain processes → publishes OrderConfirmed event to Internal Event Bus → Analytics Adapter forwards to Kafka analytics cluster. OUTBOUND TO DHL: Core Domain publishes ShipmentCreated → DHL Adapter subscribes, calls DHL REST API → DHL eventually sends webhook callback → Webhook Gateway ACKs in <500ms and enqueues → DHL Adapter consumes, translates → issues RecordDeliveryStatus command → Core Domain publishes DeliveryAttempted/Completed/Failed → Analytics Adapter forwards. ALL EVENTS: Internal Event Bus serves as the single source of truth for event routing. Every domain event is consumed by the Analytics Adapter for the real-time stream to System C.",
    "patterns_used": [
      {
        "pattern": "Anti-Corruption Layer (ACL)",
        "rationale": "Each external system has a radically different protocol, data format, and vocabulary. ACLs prevent SAP's XML/IDoc model, DHL's REST model, and the analytics schema from leaking into the core domain. When any external system changes its API, only the corresponding adapter changes."
      },
      {
        "pattern": "Event-Driven Architecture with Internal Event Bus",
        "rationale": "The three integrations have fundamentally different timing characteristics (batch/15min, real-time/webhooks, streaming). An event bus decouples producers from consumers, allowing each integration to operate at its natural cadence without blocking others."
      },
      {
        "pattern": "CQRS-lite (Command/Event separation)",
        "rationale": "Inbound integrations issue commands to the core domain; outbound integrations subscribe to events. This separates the 'request to change state' flow from the 'react to state change' flow, making the system easier to reason about and test."
      },
      {
        "pattern": "Webhook Fast-ACK with Async Processing",
        "rationale": "DHL's 500ms webhook SLA makes synchronous processing risky. The gateway ACKs immediately and enqueues, guaranteeing we never miss a callback due to slow processing. This is a standard pattern for webhook-heavy integrations."
      },
      {
        "pattern": "Outbox Pattern (for SAP Adapter outbound)",
        "rationale": "When generating outbound XML files for SAP, we write to an outbox table in the same transaction as the domain state change, then a separate process flushes the outbox to SFTP. This prevents the 'dual write' problem where domain state updates but the file never gets written (or vice versa)."
      },
      {
        "pattern": "Idempotent Consumer",
        "rationale": "All adapters implement idempotent message processing. SAP Adapter tracks processed filenames. DHL Adapter deduplicates by webhook delivery ID. Analytics Adapter uses Kafka consumer offsets. This makes retries safe across the board."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Order Management",
        "classification": "core",
        "aggregates": [
          "Order (root: orderId) — states: Placed → Confirmed → Shipped → Delivered/Failed. Invariants: cannot confirm an already-shipped order, cannot create shipment for unconfirmed order."
        ]
      },
      {
        "name": "Shipment Management",
        "classification": "core",
        "aggregates": [
          "Shipment (root: shipmentId) — states: Created → InTransit → Delivered/Failed. Linked to Order via orderId. Invariants: one active shipment per order, delivery status transitions are monotonic."
        ]
      },
      {
        "name": "ERP Integration",
        "classification": "supporting",
        "aggregates": [
          "SFTPFileTracker (root: fileName) — tracks processed/pending/failed files for idempotency.",
          "OutboundXMLDocument (root: documentId) — outbox for SAP-bound XML documents."
        ]
      },
      {
        "name": "Carrier Integration",
        "classification": "supporting",
        "aggregates": [
          "CarrierShipmentMapping (root: shipmentId) — maps internal shipmentId to DHL tracking number and manages API interaction state.",
          "WebhookDelivery (root: deliveryId) — deduplication ledger for incoming webhooks."
        ]
      },
      {
        "name": "Analytics Integration",
        "classification": "generic",
        "aggregates": [
          "EventProjection — stateless transformer, no aggregates needed. Consumer offset tracking handled by Kafka consumer group."
        ]
      }
    ],
    "context_map": [
      {
        "upstream": "Order Management",
        "downstream": "ERP Integration",
        "relationship": "Customer-Supplier. Order Management defines the canonical order model. ERP Integration conforms to it and translates to/from SAP's vocabulary."
      },
      {
        "upstream": "Order Management",
        "downstream": "Shipment Management",
        "relationship": "Shared Kernel (minimal). Both contexts share the orderId and a small set of order status values. Kept intentionally thin."
      },
      {
        "upstream": "Shipment Management",
        "downstream": "Carrier Integration",
        "relationship": "Customer-Supplier. Shipment Management publishes ShipmentCreated. Carrier Integration translates to DHL API calls and translates callbacks back into domain commands."
      },
      {
        "upstream": "Order Management + Shipment Management",
        "downstream": "Analytics Integration",
        "relationship": "Conformist. Analytics Integration conforms to whatever events the core contexts publish. It has no influence on the upstream model — it adapts."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Kafka as the Internal Event Bus (not RabbitMQ, not in-process)",
      "gains": "Durable event log enables replay for debugging and reprocessing. Natural fit since System C already requires Kafka. Supports high throughput and consumer groups for scaling adapters independently. Ordering guarantees per partition (partitioned by orderId).",
      "sacrifices": "Operational complexity of running Kafka (or managed Kafka). Higher latency than in-process event dispatch (~5-20ms). Requires schema management discipline.",
      "alternatives_considered": ["RabbitMQ — simpler ops but no durable log replay, would still need Kafka for System C creating two messaging systems", "In-process event bus — zero latency but couples all adapters into a single deployment unit, defeating fault isolation"]
    },
    {
      "decision": "Webhook Fast-ACK pattern (enqueue then process) vs synchronous webhook processing",
      "gains": "Guarantees sub-500ms response to DHL. Decouples webhook receipt from processing complexity. Allows processing retries without losing the webhook.",
      "sacrifices": "Eventual consistency — there is a small delay between DHL notifying us and the domain state updating. Adds an intermediate queue to operate.",
      "alternatives_considered": ["Synchronous processing — simpler but risks timeout under load or during downstream issues, risking DHL marking our webhook as failed and retrying/disabling it"]
    },
    {
      "decision": "Separate adapters as distinct deployable units vs monolith with adapters as modules",
      "gains": "Independent scaling (DHL adapter may need 3x instances during peak delivery hours while SAP adapter is fine with 1). Independent failure domains. Independent deploy cycles.",
      "sacrifices": "More deployment units to manage. Distributed system complexity. Need service discovery or shared config for Kafka broker addresses.",
      "alternatives_considered": ["Monolith with adapter modules — simpler deployment but SAP SFTP polling failures could impact DHL webhook processing if they share a process"]
    },
    {
      "decision": "Outbox pattern for SAP outbound vs direct SFTP write after domain event",
      "gains": "Atomic consistency — domain state change and outbound message are committed together. No lost or phantom XML files.",
      "sacrifices": "Slightly more complex implementation. Requires a polling or CDC mechanism to flush the outbox to SFTP.",
      "alternatives_considered": ["Direct SFTP write — simpler but creates dual-write problem where domain commits but SFTP fails (or vice versa), leading to data inconsistency"]
    }
  ],

  "flexibility_points": [
    {
      "area": "Carrier Integration",
      "evolution_path": "Adding a second carrier (FedEx, UPS) requires only a new adapter behind the same ACL boundary. The core domain publishes the same ShipmentCreated event. A carrier routing service can be introduced to select the adapter based on business rules. Zero changes to core domain."
    },
    {
      "area": "Analytics Schema",
      "evolution_path": "The Analytics Adapter owns its own schema transformation. If the analytics platform changes its required format, only this adapter changes. A Schema Registry enables backward-compatible evolution. Adding new event types to the analytics stream requires only subscribing the adapter to a new topic."
    },
    {
      "area": "ERP System Replacement",
      "evolution_path": "If SAP is replaced with another ERP, only the SAP Adapter is rewritten. The command interface to the Core Domain (ConfirmOrder, etc.) remains stable. The new ERP adapter just needs to produce the same commands."
    },
    {
      "area": "Event Replay and Reprocessing",
      "evolution_path": "Kafka's durable log allows replaying events to rebuild analytics state, backfill a new integration, or debug production issues. Consumer groups can be reset to reprocess from any offset."
    }
  ],

  "rigidity_points": [
    {
      "area": "Domain Event Schema",
      "reason": "The canonical event schema (eventType, orderId, timestamp, version, payload) is the contract everything depends on. Changing it requires coordinated updates across all adapters. This is intentional — the core domain model should be stable and change slowly, and all external volatility should be absorbed by the ACLs."
    },
    {
      "area": "Order Lifecycle State Machine",
      "reason": "The state transitions (Placed → Confirmed → Shipped → Delivered/Failed) encode fundamental business rules. Adding or reordering states is a significant change that propagates to all contexts. This rigidity protects business invariants."
    },
    {
      "area": "Kafka Topic Structure",
      "reason": "Topic names and partitioning strategy (by orderId) are load-bearing infrastructure decisions. Changing them requires coordinated consumer migration. Design them carefully upfront."
    }
  ],

  "risks": [
    {
      "risk": "SAP SFTP file processing fails silently — files accumulate unprocessed and orders are never confirmed, causing downstream shipment delays.",
      "severity": "critical",
      "mitigation": "Implement a staleness monitor: if no files have been successfully processed in 30 minutes (2x the 15-minute polling interval), fire an alert. Track processed file count as a metric. Add a health check endpoint that reports last-successful-poll timestamp."
    },
    {
      "risk": "DHL webhook endpoint becomes unreachable or slow, causing DHL to stop sending callbacks (most webhook providers disable endpoints after repeated failures).",
      "severity": "critical",
      "mitigation": "The fast-ACK gateway minimizes this risk. Additionally: deploy the webhook gateway behind a load balancer with health checks, implement synthetic webhook testing, and build a DHL API polling fallback that periodically queries shipment status as a safety net."
    },
    {
      "risk": "Kafka Internal Event Bus goes down, halting all integration data flow simultaneously.",
      "severity": "high",
      "mitigation": "Run Kafka with replication factor ≥ 3 across availability zones (or use a managed service like Confluent/MSK). Each adapter should have circuit breakers that buffer locally during brief outages. The SAP Adapter is naturally resilient (files persist on SFTP). The DHL webhook gateway should have a local buffer (Redis Stream) that can survive a Kafka outage."
    },
    {
      "risk": "Schema drift between the internal domain events and the analytics platform's expected format causes silent data quality issues in reporting.",
      "severity": "medium",
      "mitigation": "Use a Schema Registry (e.g., Confluent Schema Registry) with compatibility checks on every deployment. The Analytics Adapter should validate outbound events against the registered schema and route invalid events to a DLQ for investigation."
    },
    {
      "risk": "Duplicate event processing — SAP sends the same file twice, or DHL sends duplicate webhook callbacks, leading to duplicate domain state changes.",
      "severity": "medium",
      "mitigation": "Idempotent consumers at every boundary. SAP: deduplicate by filename + checksum. DHL: deduplicate by webhook deliveryId. Core Domain: deduplicate commands by correlationId. All deduplication checks use a sliding window (e.g., 7 days) to bound storage."
    },
    {
      "risk": "Ordering anomalies — a DeliveryCompleted event arrives at the analytics platform before the corresponding ShipmentCreated event due to different processing paths.",
      "severity": "low",
      "mitigation": "Partition all Kafka topics by orderId to guarantee per-order event ordering. The Analytics Adapter should consume from all relevant topics in a deterministic order, or the analytics platform should handle out-of-order events with event timestamps and late-arrival windows."
    }
  ],

  "implementation_guidance": {
    "recommended_approach": "Build incrementally in this order: (1) Core Domain with Internal Event Bus — get the event backbone working with in-memory tests first. (2) Analytics Adapter — simplest integration, proves the event bus works end-to-end. (3) DHL Carrier Adapter — highest real-time requirements, validates the webhook fast-ACK pattern. (4) SAP ERP Adapter — batch nature makes it forgiving, and by this point the patterns are proven. Each adapter should be developed and deployed independently with its own CI/CD pipeline.",
    "files_to_create_or_modify": [
      "src/core/domain/events/ — Domain event definitions (OrderPlaced.ts, ShipmentCreated.ts, etc.)",
      "src/core/domain/aggregates/ — Order.ts, Shipment.ts with state machines",
      "src/infrastructure/eventbus/ — Kafka producer/consumer wrappers, topic configuration",
      "src/adapters/sap/ — SFTPPoller, XMLParser, SAPTranslator, OutboxFlusher",
      "src/adapters/dhl/ — WebhookGateway, DHLApiClient, DHLTranslator, WebhookDeduplicator",
      "src/adapters/analytics/ — AnalyticsEventTransformer, SchemaValidator, AnalyticsProducer",
      "src/infrastructure/dlq/ — DeadLetterQueue, RetryScheduler, AlertPublisher",
      "config/kafka-topics.yaml — Topic definitions, partition counts, retention policies",
      "docker-compose.yaml — Local development setup with Kafka, Redis, SFTP mock"
    ],
    "patterns_to_follow": "Hexagonal Architecture (Ports & Adapters): Core domain defines ports (interfaces); each integration implements an adapter. All adapters depend inward on the core domain, never the reverse. Use dependency injection to wire adapters at startup. Each adapter owns its own error handling, retry logic, and health check. Use structured logging with correlationId propagated through all events and commands for end-to-end traceability.",
    "pitfalls_to_avoid": [
      "Do NOT let SAP XML schemas leak into the core domain model — the ACL must fully translate",
      "Do NOT process DHL webhooks synchronously — always fast-ACK and enqueue",
      "Do NOT share Kafka consumer groups between adapters — each adapter gets its own group for independent scaling and failure isolation",
      "Do NOT use a single DLQ for all adapters — per-adapter DLQs prevent one noisy integration from burying another's failures",
      "Do NOT skip idempotency — every external system WILL send duplicates eventually",
      "Do NOT couple the Analytics Adapter to specific event types with a whitelist — subscribe to all domain events and transform generically, so new event types flow automatically"
    ]
  },

  "escalations": [],

  "confidence": {
    "level": 85,
    "high_confidence_areas": [
      "ACL per external system is the correct boundary pattern — the three systems have incompatible protocols, schemas, and timing",
      "Event-driven backbone with Kafka — the analytics streaming requirement makes this the natural choice, and it unifies all integration routing",
      "Webhook fast-ACK pattern — the 500ms SLA makes async processing mandatory",
      "Outbox pattern for SAP outbound — dual-write avoidance is well-understood and essential"
    ],
    "low_confidence_areas": [
      "Exact Kafka topic partitioning strategy may need adjustment based on actual order volume and distribution — if a few large customers dominate, orderId partitioning could create hot partitions",
      "Whether the SAP integration should be purely file-based or if SAP also supports RFC/BAPI calls that could reduce latency — depends on the specific SAP deployment",
      "Sizing of the webhook ingestion buffer — Redis Stream vs Kafka topic depends on existing infrastructure and ops team familiarity"
    ],
    "assumptions": [
      "SAP SFTP is the only available integration method (no SAP RFC/OData)",
      "DHL webhook callbacks include a unique deliveryId for deduplication",
      "The analytics Kafka cluster is a separate cluster from the internal event bus (common in enterprises for isolation)",
      "Order volumes are moderate (thousands/day, not millions) — at millions/day the partitioning strategy needs more careful design",
      "The team has Kafka operational experience or is using a managed Kafka service"
    ]
  }
}
